const TEMA_KEY    = 'panini2026_tema';
let estado = {};       // { "1": 0, "21": 2, "CC3": 1, ... }
let filtroEstado = 'todas';
let filtroSeccion = '';

// --- Modo oscuro ---
function toggleTema() {
  const oscuro = document.body.classList.toggle('dark');
  localStorage.setItem(TEMA_KEY, oscuro ? 'dark' : 'light');
  const btn = document.getElementById('btn-tema');
  btn.textContent = oscuro ? '☀️ Modo claro' : '🌙 Modo oscuro';
}

function cargarTema() {
  const tema = localStorage.getItem(TEMA_KEY);
  if (tema === 'dark') {
    document.body.classList.add('dark');
    const btn = document.getElementById('btn-tema');
    if (btn) btn.textContent = '☀️ Modo claro';
  }
}
 
// --- Persistencia ---
function guardar() {
  localStorage.setItem(STORAGE_KEY, JSON.stringify(estado));
}
 
function cargar() {
  try {
    const raw = localStorage.getItem(STORAGE_KEY);
    if (raw) estado = JSON.parse(raw);
  } catch(e) { estado = {}; }
}
 
// --- Helpers ---
function getValor(fig) {
  return estado[String(fig.id)] || 0;
}
 
function getEstadoFig(fig) {
  const v = getValor(fig);
  if (v === 0) return 'falta';
  if (v === 1) return 'tengo';
  return 'repetida';
}
 
// --- Stats ---
function actualizarStats() {
  let tengo = 0, faltan = 0, repet = 0;
  for (const fig of ALBUM) {
    const v = getValor(fig);
    if (v === 0) faltan++;
    else tengo++;
    if (v > 1) repet += (v - 1);
  }
  document.getElementById('s-total').textContent = ALBUM.length;
  document.getElementById('s-tengo').textContent = tengo;
  document.getElementById('s-faltan').textContent = faltan;
  document.getElementById('s-repet').textContent = repet;
}
 
// --- Secciones ---
function getSecciones() {
  const vistas = new Set();
  const orden = [];
  for (const fig of ALBUM) {
    if (!vistas.has(fig.seccion)) {
      vistas.add(fig.seccion);
      orden.push(fig.seccion);
    }
  }
  return orden;
}
 
function poblarSelectSeccion() {
  const sel = document.getElementById('filtro-seccion');
  for (const s of getSecciones()) {
    const opt = document.createElement('option');
    opt.value = s;
    opt.textContent = s;
    sel.appendChild(opt);
  }
}
 
// --- Filtros ---
function setEstado(f, el) {
  filtroEstado = f;
  document.querySelectorAll('.chip').forEach(c => c.classList.remove('activo'));
  el.classList.add('activo');
  renderizar();
}
 
function aplicarFiltros() {
  filtroSeccion = document.getElementById('filtro-seccion').value;
  renderizar();
}
 
// --- Render ---
function renderizar() {
  const main = document.getElementById('main');
  main.innerHTML = '';
 
  // Agrupar por sección
  const grupos = {};
  for (const fig of ALBUM) {
    if (!grupos[fig.seccion]) grupos[fig.seccion] = [];
    grupos[fig.seccion].push(fig);
  }
 
  let hayAlgo = false;
 
  for (const seccion of getSecciones()) {
    // Filtro de sección
    if (filtroSeccion && filtroSeccion !== seccion) continue;
 
    const figs = grupos[seccion];
 
    // Filtrar por estado
    const figsFiltradas = figs.filter(fig => {
      if (filtroEstado === 'todas') return true;
      return getEstadoFig(fig) === filtroEstado;
    });
 
    if (figsFiltradas.length === 0) continue;
    hayAlgo = true;
 
    // Contar tengo en esta sección
    const tengoEnSec = figs.filter(f => getValor(f) > 0).length;
 
    const div = document.createElement('div');
    div.className = 'seccion';
 
    // Header de sección
    const header = document.createElement('div');
    header.className = 'seccion-header';
    header.innerHTML = `
      <span class="seccion-titulo">${seccion}</span>
      <span class="seccion-progreso">${tengoEnSec}/${figs.length}</span>
    `;
    div.appendChild(header);
 
    // Grilla
    const grilla = document.createElement('div');
    grilla.className = 'grilla';
 
    for (const fig of figsFiltradas) {
      grilla.appendChild(crearFigurita(fig));
    }
 
    div.appendChild(grilla);
    main.appendChild(div);
  }
 
  if (!hayAlgo) {
    main.innerHTML = '<div class="vacio">No hay figuritas con ese filtro.</div>';
  }
 
  actualizarStats();
}
 
function crearFigurita(fig) {
  const est = getEstadoFig(fig);
  const extra = Math.max(0, getValor(fig) - 1);
 
  const el = document.createElement('div');
  el.className = 'fig' + (est !== 'falta' ? ' ' + est : '');
 
  // Número / ID visible
  const label = typeof fig.id === 'string' ? fig.id : String(fig.nroEquipo);
  el.innerHTML = `<span>${label}</span>`;
 
  // Tipo abreviado
  if (fig.tipo !== 'Jugador') {
    const tipoEl = document.createElement('span');
    tipoEl.className = 'fig-tipo';
    tipoEl.textContent = fig.tipo.slice(0, 3).toUpperCase();
    el.appendChild(tipoEl);
  }
 
  // Badge de repetidas
  if (extra > 0) {
    const badge = document.createElement('span');
    badge.className = 'badge';
    badge.textContent = '+' + extra;
    el.appendChild(badge);
  }
 
  // --- Eventos ---
  // Clic izquierdo: ciclo falta → tengo → falta
  el.addEventListener('click', () => {
    const v = getValor(fig);
    estado[String(fig.id)] = v === 0 ? 1 : 0;
    guardar();
    renderizar();
  });
 
  // Clic derecho: sumar repetida (si ya tengo) o bajar contador
  el.addEventListener('contextmenu', (e) => {
    e.preventDefault();
    const v = getValor(fig);
    if (v === 0) {
      estado[String(fig.id)] = 1;        // primero la marco como tengo
    } else {
      estado[String(fig.id)] = v + 1;    // sumo repetida
    }
    guardar();
    renderizar();
  });
 
  // Tooltip
  el.addEventListener('mouseenter', (e) => {
    const tip = document.getElementById('tooltip');
    const nombre = fig.jugador || `${fig.seccion} #${fig.nroEquipo}`;
    const estado_txt = est === 'falta' ? 'Falta' : est === 'tengo' ? 'Tengo' : `Tengo + ${extra} repetida${extra > 1 ? 's' : ''}`;
    tip.innerHTML = `<strong>${nombre}</strong><br>${fig.seccion} · ${fig.tipo}<br>${estado_txt}`;
    tip.style.display = 'block';
    posTooltip(e);
  });
 
  el.addEventListener('mousemove', posTooltip);
  el.addEventListener('mouseleave', () => {
    document.getElementById('tooltip').style.display = 'none';
  });
 
  return el;
}
 
function posTooltip(e) {
  const tip = document.getElementById('tooltip');
  tip.style.left = (e.clientX + 14) + 'px';
  tip.style.top  = (e.clientY + 14) + 'px';
}
 
// ================================================================
//  INIT
// ================================================================
cargarTema();
cargar();
poblarSelectSeccion();
renderizar();



function exportar() {
  // Arma el objeto con fecha y estado
  const backup = {
    fecha: new Date().toISOString(),
    version: 1,
    estado: estado
  };

  // Crea un archivo .json y lo descarga
  const blob = new Blob([JSON.stringify(backup, null, 2)], { type: 'application/json' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = `figuritas-backup-${new Date().toLocaleDateString('es-AR').replace(/\//g, '-')}.json`;
  a.click();
  URL.revokeObjectURL(url);
}

function importar() {
  // Abre el selector de archivo
  document.getElementById('file-importar').click();
}

function cargarArchivo(event) {
  const archivo = event.target.files[0];
  if (!archivo) return;

  const reader = new FileReader();
  reader.onload = (e) => {
    try {
      const backup = JSON.parse(e.target.result);

      // Valida que el archivo tenga la estructura correcta
      if (!backup.estado) {
        alert('El archivo no parece ser un backup válido.');
        return;
      }

      if (confirm(`¿Importar progreso guardado el ${new Date(backup.fecha).toLocaleString('es-AR')}? Esto reemplaza el progreso actual.`)) {
        estado = backup.estado;
        guardar();
        renderizar();
        alert('¡Progreso importado correctamente!');
      }
    } catch(e) {
      alert('Error al leer el archivo. Asegurate de que sea un backup válido.');
    }
  };
  reader.readAsText(archivo);

  // Resetea el input para que puedas importar el mismo archivo dos veces si hace falta
  event.target.value = '';
}